#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int is_chet(int n) {
    return n % 2 == 0 ? 1 : 0;
}

int pixel(char* input) {
    int red, green, blue;
    sscanf(input, "%d %d %d", &red, &green, &blue);

    int plist[3] = {red, green, blue};
    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 2 - i; j++) {
            if (plist[j] > plist[j + 1]) {
                int temp = plist[j];
                plist[j] = plist[j + 1];
                plist[j + 1] = temp;
            }
        }
    }

    int lowestChet = is_chet(plist[0]);
    int midChet = is_chet(plist[1]);

    if ((midChet + lowestChet) == 2 || (midChet + lowestChet) == 0) {
        return plist[1];
    } else {
        return plist[2];
    }
}

int main() {
    char input[100];
    fgets(input, sizeof(input), stdin);
    printf("%d\n", pixel(input));
    return 0;
